class Solution {
    public double minTime(int n, int k, int m, int[] time, double[] mul) {
        Arrays.sort(time);
        int maskCount = 1 << n;
        double[][] dp = new double[m][maskCount];
        for (double[] d : dp) {
            Arrays.fill(d, -1);
        }
        return dfs(0, (1 << n) - 1, n, k, m, time, mul, dp);
    }

    private double dfs(int stage, int mask, int n, int k, int m, int[] time, double[] mul, double[][] dp) {
        if (mask == 0) return 0;
        if (dp[stage][mask] != -1) return dp[stage][mask];
        double res = Double.MAX_VALUE;
        for (int i = 1; i <= k && i <= n; i++) {
            for (int subMask = mask; subMask > 0; subMask = (subMask - 1) & mask) {
                if (Integer.bitCount(subMask) == i) {
                    int maxTime = 0;
                    for (int j = 0; j < n; j++) {
                        if (((subMask >> j) & 1) == 1) maxTime = Math.max(maxTime, time[j]);
                    }
                    double crossTime = maxTime * mul[stage];
                    int nextStage = (stage + (int) crossTime) % m;
                    double returnTime = time[Integer.numberOfTrailingZeros(subMask)] * mul[nextStage];
                    int nextMask = mask ^ subMask;
                    double totalTime = crossTime + (i < n ? returnTime + dfs(nextStage, nextMask, n, k, m, time, mul, dp) : 0);
                    res = Math.min(res, totalTime);
                }
            }
        }
        return dp[stage][mask] = res;
    }
}
